__kernel void srad_kernel(
    const float lambda,
    const int rows,
    const int cols,
    const long size_I,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global float* dN,
    __global float* dS,
    __global float* dW,
    __global float* dE,
    __global float* c,
    __global float* J,
    const float q0sqr)
{
    int gid = get_global_id(0);
    if (gid >= size_I) return;

    int i = gid / cols;
    int j = gid % cols;

    // Clamp indices to valid range to avoid out-of-bounds
    int iN_idx = iN[i];
    if (iN_idx < 0) iN_idx = 0;
    if (iN_idx >= rows) iN_idx = rows - 1;

    int iS_idx = iS[i];
    if (iS_idx < 0) iS_idx = 0;
    if (iS_idx >= rows) iS_idx = rows - 1;

    int jW_idx = jW[j];
    if (jW_idx < 0) jW_idx = 0;
    if (jW_idx >= cols) jW_idx = cols - 1;

    int jE_idx = jE[j];
    if (jE_idx < 0) jE_idx = 0;
    if (jE_idx >= cols) jE_idx = cols - 1;

    float Jc = J[gid];
    if (Jc == 0.0f) {
        // Avoid division by zero
        c[gid] = 0.0f;
        dN[gid] = 0.0f;
        dS[gid] = 0.0f;
        dW[gid] = 0.0f;
        dE[gid] = 0.0f;
        return;
    }

    float dN_val = J[iN_idx * cols + j] - Jc;
    float dS_val = J[iS_idx * cols + j] - Jc;
    float dW_val = J[i * cols + jW_idx] - Jc;
    float dE_val = J[i * cols + jE_idx] - Jc;

    dN[gid] = dN_val;
    dS[gid] = dS_val;
    dW[gid] = dW_val;
    dE[gid] = dE_val;

    float G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
    float L = (dN_val + dS_val + dW_val + dE_val) / Jc;

    float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
    float den = 1.0f + 0.25f * L;
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c_val = 1.0f / (1.0f + den);

    if (c_val < 0.0f) c_val = 0.0f;
    else if (c_val > 1.0f) c_val = 1.0f;

    c[gid] = c_val;
}

__kernel void srad2_kernel(
    const float lambda,
    const int rows,
    const int cols,
    const long size_I,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global const float* dN,
    __global const float* dS,
    __global const float* dW,
    __global const float* dE,
    __global const float* c,
    __global float* J)
{
    int gid = get_global_id(0);
    if (gid >= size_I) return;

    int i = gid / cols;
    int j = gid % cols;

    // Clamp indices to valid range to avoid out-of-bounds
    int iS_idx = iS[i];
    if (iS_idx < 0) iS_idx = 0;
    if (iS_idx >= rows) iS_idx = rows - 1;

    int jE_idx = jE[j];
    if (jE_idx < 0) jE_idx = 0;
    if (jE_idx >= cols) jE_idx = cols - 1;

    float cN = c[gid];
    float cS = c[iS_idx * cols + j];
    float cW = c[gid];
    float cE = c[i * cols + jE_idx];

    float D = cN * dN[gid] + cS * dS[gid] + cW * dW[gid] + cE * dE[gid];

    J[gid] = J[gid] + 0.25f * lambda * D;
}
